import java.io.IOException;
import java.io.PrintWriter;

import org.owasp.encoder.Encode;

public class XSSSecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!');</script>";

        // Escaping user input for safe output
        String escapedUserInput = Encode.forHtml(userInput);

        System.out.println("User Input: " + escapedUserInput);

        try {
            PrintWriter out = new PrintWriter("output.html");
            out.println("<html>");
            out.println("<body>");
            out.println("<h1>User Input: " + escapedUserInput + "</h1>");
            out.println("</body>");
            out.println("</html>");
            out.close();

            System.out.println("Output HTML file generated successfully.");
        } catch (IOException e) {
            System.out.println("Error generating output HTML file: " + e.getMessage());
        }
    }
}

